import { useNavigate } from "react-router-dom";
import PlannerShell from "../components/PlannerShell";
import ProgressBar from "../components/ProgressBar";

const steps = [
  { label: "Checking transport", done: true, icon: "✓" },
  { label: "Finding stay", done: true, icon: "✓" },
  { label: "Calculating budget", done: false, active: true, icon: "…" },
];

const Loading = () => {
  const navigate = useNavigate();
  return (
    <PlannerShell
      mobileHeaderLeft={<span style={{ width: 40 }} />}
      mobileHeaderRight={<span style={{ width: 40 }} />}
    >
      <div className="planner-container--loading planner-loading-flex planner-loading-inner">
        <ProgressBar activeStep={4} />

        <div className="loading-spinner" />
        <h2 className="d-loading-title">Building your trip plan</h2>
        <p className="d-loading-sub">Searching best options within ₹15,000 for 5 days to Manali</p>

        <div className="d-load-steps">
          {steps.map((s, i) => (
            <div
              key={i}
              className={`d-load-step${s.done ? " d-load-step--done" : ""}${s.active ? " d-load-step--active" : ""}`}
            >
              <span className="d-load-step-glyph" aria-hidden="true">{s.icon}</span>
              <span className="d-load-step-text">{s.label}</span>
            </div>
          ))}
        </div>

        <div className="d-load-prog-track">
          <div className="d-load-prog-fill" style={{ width: "45%" }} />
        </div>
        <p className="d-load-prog-label">45% complete</p>

        <button
          type="button"
          className="secondary-btn"
          style={{ maxWidth: 240, marginTop: 8 }}
          onClick={() => navigate("/plan")}
        >
          Skip — show plan now
        </button>
      </div>
    </PlannerShell>
  );
};

export default Loading;
